class Solution:
    def countLargestGroup(self, n: int) -> int:
        digit_sum_count = {}
        max_size = 0
        max_size_count = 0
        for i in range(1, n + 1):
            digit_sum = sum(int(digit) for digit in str(i))
            if digit_sum not in digit_sum_count:
                digit_sum_count[digit_sum] = 1
            else:
                digit_sum_count[digit_sum] += 1
            if digit_sum_count[digit_sum] > max_size:
                max_size = digit_sum_count[digit_sum]
                max_size_count = 1
            elif digit_sum_count[digit_sum] == max_size:
                max_size_count += 1
        return max_size_count
